const crypto = require('crypto');
const https = require('https');

// Parse credentials from connection string (mirrors blobstorage.js approach)
const connectionString = $env.AZURE_STORAGE_CONNECTION_STRING || $env.AZURE_BLOB_CONNECTION_STRING;
let accountName, accountKey;
if (connectionString) {
  accountName = connectionString.match(/AccountName=([^;]+)/)?.[1];
  accountKey  = connectionString.match(/AccountKey=([^;]+)/)?.[1];
}
// Fallback to individual env vars if connection string not set
if (!accountName) accountName = $env.AZURE_STORAGE_ACCOUNT_NAME || 'unificdmpblob';
if (!accountKey)  accountKey  = $env.AZURE_STORAGE_ACCOUNT_KEY;

if (!accountKey) {
  throw new Error(
    'Azure credentials not found. Set AZURE_STORAGE_CONNECTION_STRING ' +
    '(e.g. "DefaultEndpointsProtocol=https;AccountName=...;AccountKey=...;EndpointSuffix=core.windows.net") ' +
    'in the n8n container environment.'
  );
}

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      const chunks = [];
      res.on('data', chunk => chunks.push(chunk));
      res.on('end', () => resolve({
        buffer: Buffer.concat(chunks),
        statusCode: res.statusCode,
        contentType: res.headers['content-type'] || 'application/octet-stream'
      }));
      res.on('error', reject);
    }).on('error', reject);
  });
}

function generateSasUrl(container, blobPath, sr = 'b', permissions = 'r') {
  const now = new Date();
  const expiry = new Date(now.getTime() + 3600000); // 1 hour
  const sv = '2020-12-06';
  const fmt = (d) => d.toISOString().replace(/\.\d{3}Z$/, 'Z');
  const st = fmt(now);
  const se = fmt(expiry);
  const canonicalizedResource = `/blob/${accountName}/${container}/${blobPath}`;
  // sv=2020-12-06: 16 fields, 15 \n, NO trailing newline (signedEncryptionScope added)
  const stringToSign = [permissions, st, se, canonicalizedResource, '', '', 'https', sv, sr, '', '', '', '', '', '', ''].join('\n');
  const key = Buffer.from(accountKey, 'base64');
  const sig = crypto.createHmac('sha256', key).update(Buffer.from(stringToSign, 'utf8')).digest('base64');
  // Build query string manually — URLSearchParams is not available in the n8n task runner VM sandbox
  const qs = 'sv='  + encodeURIComponent(sv)
           + '&sr=b'
           + '&sp=r'
           + '&st='  + encodeURIComponent(st)
           + '&se='  + encodeURIComponent(se)
           + '&spr=https'
           + '&sig=' + encodeURIComponent(sig);
  return `https://${accountName}.blob.core.windows.net/${container}/${blobPath}?${qs}`;
}

async function fetchBlob(container, blobPath) {
  const sasUrl = generateSasUrl(container, blobPath);
  const { buffer, statusCode, contentType } = await httpsGet(sasUrl);
  if (statusCode !== 200) {
    throw new Error(`Azure Blob download failed HTTP ${statusCode} for ${container}/${blobPath}. Body: ${buffer.toString().substring(0, 300)}`);
  }
  return { buffer, contentType };
}

const items = $input.all();
const result = [];

for (const item of items) {
  // Pass through if binary already present (direct file upload path)
  if (item.binary && Object.keys(item.binary).length > 0) {
    result.push(item);
    continue;
  }

  // Normalize: test webhook wraps body under item.json.body; production uses item.json directly
  const bodyData  = item.json.body || item.json;
  const blobPath  = bodyData.blobPath;
  const blobFiles = bodyData.blobFiles;

  if (!blobPath && !blobFiles) {
    result.push(item);
    continue;
  }

  if (!item.binary) item.binary = {};

  if (blobPath) {
    // Single-file mode: { "blobPath": "folder/file.pdf", "azureContainer": "compliance" }
    const container = bodyData.azureContainer || 'compliance';
    const { buffer, contentType } = await fetchBlob(container, blobPath);
    const fileName = blobPath.split('/').pop();
    item.binary.data = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    item.json.azureBlobFetched = true;
    item.json.originalFileName = fileName;
  }

  if (blobFiles) {
    // Multi-file mode: { "file0": "path.pdf" } or { "file0": { "blobPath": "...", "container": "..." } }
    for (const [fieldName, blobInfo] of Object.entries(blobFiles)) {
      const bp = typeof blobInfo === 'string' ? blobInfo : blobInfo.blobPath;
      const container = (typeof blobInfo === 'object' && blobInfo.container)
        ? blobInfo.container
        : (item.json.azureContainer || 'compliance');
      const { buffer, contentType } = await fetchBlob(container, bp);
      const fileName = bp.split('/').pop();
      item.binary[fieldName] = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    }
    item.json.azureBlobFetched = true;
  }

  result.push(item);
}

return result;
